#include <iostream>
#include <iomanip>
#include <vector>
#include <sstream>

class TemperatureConverter {
private:
    double celsius;

public:
    void setCelsius(double c) {
        celsius = c;
    }

    double getFahrenheit() {
        return celsius * 1.8 + 32.0;
    }
};

int main() {
    std::ostringstream oss;
    oss << std::fixed << std::setprecision(2);

    // Test case 1: Robustness issue
    TemperatureConverter tc_robust;
    oss << "Undefined behavior: Accessing uninitialized 'celsius' member. Output value is unpredictable.\n";

    // Test case 2-5: Standard cases
    std::vector<std::pair<double, double>> testData = {
        {25.0, 77.00}, {0.0, 32.00}, {100.0, 212.00}, {-40.0, -40.00}
    };
    TemperatureConverter converter;

    for (const auto& test : testData) {
        converter.setCelsius(test.first);
        oss << converter.getFahrenheit() << "\n";
    }

    std::cout << oss.str();
    return 0;
}
